-- Enrichment marathon batch: ServiceTitan, Sessionize, Setmore, SevenRooms, Shaarli, Shaper, ShareFile, SharpCloud

-- ── ServiceTitan ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$ServiceTitan is a cloud-based operations platform for trades businesses, giving HVAC, plumbing, electrical, roofing, and similar companies one system for scheduling, dispatch, CRM, marketing, invoicing, and payments.$q$, short_description),
  pricing_model = COALESCE($q$Custom quote-based pricing, typically billed per technician on an annual contract$q$, pricing_model),
  starting_price = COALESCE($q$From approximately $398 per month, custom quote required$q$, starting_price),
  founded_year = COALESCE(2007, founded_year),
  company_size = COALESCE($q$Approximately 2,900 employees, publicly traded on Nasdaq as TTAN$q$, company_size),
  headquarters = COALESCE($q$Glendale, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$ServiceTitan Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$See what ServiceTitan costs, who it is built for, and how its scheduling, dispatch, CRM, and marketing tools compare for HVAC, plumbing, electrical, and other trades businesses.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$ServiceTitan is a cloud-based, all-in-one operations platform purpose-built for residential and commercial trades businesses, including HVAC, plumbing, electrical, roofing, garage door, and chimney companies. Founded in 2007 by Ara Mahdessian and Vahe Kuzoyan, the company is headquartered in Glendale, California, and became publicly traded on the Nasdaq under the ticker TTAN after its December 2024 IPO, which raised roughly 625 million dollars and valued the company at approximately 8.9 billion dollars. ServiceTitan replaces the paper-based and spreadsheet workflows many trades businesses relied on with a unified system covering call booking, dispatch and scheduling, technician mobile apps, CRM, marketing automation, pricebook and estimate management, invoicing, financing, inventory, and reporting. The platform is aimed primarily at mid-size to large trades businesses with multiple technicians and trucks rather than solo operators, and pricing is not published; it is quoted per business based on technician count and modules used, with third-party sources reporting typical starting costs around 398 dollars per month plus onboarding fees that can run from several thousand to tens of thousands of dollars. ServiceTitan integrates with QuickBooks, financing providers, and marketing channels, and is widely used across North America. Competitors include Housecall Pro, Jobber, and FieldEdge. As of 2024 ServiceTitan employed approximately 2,900 people. Note: ServiceTitan is unrelated to ServiceNow, a separate enterprise IT service management company.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '6fc3837d-ade3-437f-ac16-1a4ee783c3f8';

