-- ── SevenRooms ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$SevenRooms is a hospitality operations and guest experience platform that helps restaurants, hotels, and nightlife venues manage reservations, waitlists, table management, guest CRM, and marketing in one system.$q$, short_description),
  pricing_model = COALESCE($q$Custom quote-based pricing per venue, billed on an annual contract$q$, pricing_model),
  starting_price = COALESCE($q$Approximately $499 per month per venue, custom quote required$q$, starting_price),
  founded_year = COALESCE(2011, founded_year),
  company_size = COALESCE($q$Approximately 350 to 395 employees$q$, company_size),
  headquarters = COALESCE($q$New York City, New York, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$SevenRooms Review 2026: Reservation and Guest CRM Pricing and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$See how SevenRooms handles restaurant and hospitality reservations, waitlists, guest CRM, and marketing, plus its pricing and 2025 DoorDash acquisition.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$SevenRooms is a cloud-based reservation, waitlist, table management, and guest experience platform built for restaurants, hotels, and nightlife and entertainment venues. It was founded in 2011 by Joel Montaniel, Allison Page, and Kinesh Patel, and is headquartered in New York City, with additional offices in the UK, Dubai, Australia, Singapore, and Hong Kong; the company employs roughly 350 to 400 people globally. SevenRooms lets hospitality operators manage bookings and waitlists, assign and optimize tables, capture detailed guest profiles and preferences, run email and text marketing campaigns, and access a reservation marketplace with tens of millions of DoorDash and Deliveroo diners at no per-cover fee. Pricing is not published; it is quoted per venue, and third-party operator reports put the core platform starting around 499 US dollars per month on an annual contract, with add-ons such as WhatsApp messaging priced separately. SevenRooms has raised roughly 74.4 million dollars in funding across five rounds, including an 8 million dollar round led by Comcast Ventures in 2017 and a 50 million dollar Series B led by Providence Strategic Growth in 2020. In May 2025, DoorDash announced an agreement to acquire SevenRooms for approximately 1.2 billion dollars in cash, closely integrating restaurant reservation and guest data with DoorDash's delivery and marketplace business. Competitors include OpenTable, Resy, and Tock.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '2d77d287-461d-4b2b-b185-9fa78b3a2e55';

