-- ── Shaarli ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Shaarli is a free, open-source, self-hosted bookmarking and link-sharing tool written in PHP that stores links in flat files instead of a database, making it lightweight to install on personal servers.$q$, short_description),
  pricing_model = COALESCE($q$Free and open source; self-hosted with no paid tiers$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2011, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$, $q$German$q$, $q$Japanese$q$]::text[],
  seo_title = COALESCE($q$Shaarli Review 2026: Free Self-Hosted Bookmarking Tool Features$q$, seo_title),
  seo_meta_description = COALESCE($q$Learn what Shaarli is, how the free open-source, database-free bookmarking tool works, and why self-hosters use it instead of hosted bookmark services.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Shaarli is a free, open-source, self-hosted bookmarking and link-sharing service written in PHP. It was originally created by French developer Sebastien Sauvage and first released in 2011 as a lightweight, database-free alternative to hosted bookmarking services like the discontinued Delicious. Because Shaarli stores all bookmarks in flat files rather than a database, it can be installed on almost any shared or personal web host with minimal setup and no database server required. The community-maintained fork, hosted at github.com slash shaarli slash Shaarli, is now the actively developed version of the project, with roughly 3,900 GitHub stars, more than 400 forks, and over 50 tagged releases, the latest being version 0.16.3. Shaarli is designed for a single user rather than teams, and is commonly used as a personal knowledge base, a public or private link blog, an RSS-readable bookmark archive, or a lightweight alternative to browser bookmark syncing. Key features include one-click bookmarklets for saving links, tagging, full-text search, RSS and ATOM feed generation, a plugin system, LDAP login support for single-user authentication, and a responsive interface that degrades gracefully without JavaScript. The interface has been translated into multiple languages including English, French, German, and Japanese. As free software with no company behind it, Shaarli has no pricing, no company size, and no headquarters; it is maintained by volunteer open-source contributors.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '0c2a2dac-cd9a-4339-9ab2-dfd365b2be95';

