-- ── Shaper ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Shaper is the company behind Shaper Origin, a handheld CNC router, and its companion software Shaper Studio and Shaper Hub, which let makers design, plan, and cut precise woodworking and fabrication projects.$q$, short_description),
  pricing_model = COALESCE($q$One-time hardware purchase for the Shaper Origin router, with free companion design software$q$, pricing_model),
  starting_price = COALESCE($q$Shaper Origin starts at $2,899; Shaper Studio and Shaper Hub software are free to use$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$]::text[],
  seo_title = COALESCE($q$Shaper Review 2026: Origin CNC Router and Shaper Hub Software$q$, seo_title),
  seo_meta_description = COALESCE($q$See how Shaper Origin's handheld CNC router works with the free Shaper Studio and Shaper Hub software, plus current pricing and key features.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Shaper is the maker of Shaper Origin, a handheld CNC router that pairs the portability of a standard woodworking router with the positional accuracy of a full CNC machine, along with two companion software products, Shaper Studio and Shaper Hub. The company is commonly cited as founded around 2011 or 2012 by MIT-trained engineers Alec Rivers and Ilan Moyer, and is headquartered in San Francisco, California, with a further office in Stuttgart, Germany, reflecting its manufacturing partnership with German tool maker Festool, which assembles the Origin hardware. Rather than requiring a fixed CNC bed and G-code programming, Origin uses an onboard camera, a printed reference tape system called ShaperTape, and a touchscreen display so a user can trace or auto-correct a cut path freehand while the tool keeps the bit within a small tolerance of the intended design. Shaper Studio is the company's browser and device-based design tool for creating and preparing cut files, while Shaper Hub, at hub.shapertools.com, is an online library where Origin owners can browse, download, and share community-made project designs. Both software products are provided free alongside hardware ownership rather than sold as a standalone subscription. The Shaper Origin hardware itself starts at 2,899 US dollars, with bundles that include a Workstation, Plate, or BenchPilot accessory system ranging up to roughly 5,306 dollars. Shaper primarily serves woodworkers, makers, and small fabrication shops rather than enterprise buyers.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'ed136ebf-ec30-4027-aba4-c834b251578e';

