-- ── ShareFile ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$ShareFile is a secure, cloud-based file sharing and document workflow platform for businesses, especially accounting and legal firms, offering encrypted storage, client portals, e-signatures, and workflow automation.$q$, short_description),
  pricing_model = COALESCE($q$Tiered per-user subscription, billed monthly or annually, with a 3-user minimum$q$, pricing_model),
  starting_price = COALESCE($q$From $16.50 per user per month billed annually (Advanced plan)$q$, starting_price),
  founded_year = COALESCE(2005, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Burlington, Massachusetts, United States (Progress Software); ShareFile originated in Raleigh, North Carolina$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Spanish$q$, $q$French$q$, $q$German$q$, $q$Japanese$q$, $q$Dutch$q$, $q$Portuguese$q$, $q$Korean$q$, $q$Simplified Chinese$q$, $q$Russian$q$]::text[],
  seo_title = COALESCE($q$ShareFile Review 2026: Secure File Sharing Pricing and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$See how ShareFile's Advanced, Premium, Industry Advantage, and Virtual Data Room plans compare on price and features for secure business file sharing.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$ShareFile is a secure, cloud-based file sharing and document workflow platform built for professional services firms, particularly accounting, legal, financial services, and healthcare businesses that need to exchange sensitive documents with clients. It was created in November 2005 by self-taught programmer Jesse Lipson in Raleigh, North Carolina, after his web design clients asked for a secure alternative to FTP for exchanging files. ShareFile was acquired by Citrix Systems in 2011 and operated for over a decade as Citrix ShareFile before Progress Software Corporation, a Nasdaq-listed infrastructure software company headquartered in Burlington, Massachusetts, completed an 875 million dollar acquisition of the ShareFile business in October 2024, adding more than 86,000 customers to Progress's portfolio. The platform provides encrypted cloud storage, branded and password-protected client portals, real-time co-editing, granular access controls, e-signature collection, form building, task and workflow automation, and compliance support for standards such as HIPAA, FINRA, and SEC recordkeeping rules. ShareFile is sold on a per-user subscription with a 3-user minimum, or 5 users for the Virtual Data Room tier, across four public tiers, Advanced, Premium, Industry Advantage for accounting firms, and Virtual Data Room, ranging from roughly 16.50 to 77 dollars per user per month on annual billing. The product interface and apps support numerous languages including English, Spanish, French, German, Japanese, Dutch, Portuguese, Korean, Simplified Chinese, and Russian. Competitors include Box, Dropbox Business, and Egnyte.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '2708453f-26c2-4ab0-9cc3-e26e1734570d';

