-- ── SharpCloud ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$SharpCloud is a data visualization and strategic roadmapping platform that turns spreadsheets and project data into interactive visual stories for portfolio management, roadmapping, and scenario planning.$q$, short_description),
  pricing_model = COALESCE($q$Tiered, role-based annual licensing (Creator, Collaborator, Read-Only), plus a free version$q$, pricing_model),
  starting_price = COALESCE($q$From £750 per year for the entry paid tier; a free version is also available$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$London, United Kingdom$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$SharpCloud Review 2026: Roadmapping and Visualization Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$See how SharpCloud's Creator, Collaborator, and Read-Only licenses work for portfolio management and roadmapping, plus its pricing and 2026 Lumivero acquisition.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$SharpCloud is a data visualization and strategic portfolio management platform that helps organizations turn spreadsheets, project plans, and other business data into interactive, story-based visualizations for roadmapping, portfolio management, risk management, and scenario planning. The company was founded in 2012 and is headquartered in London, United Kingdom. In January 2026, SharpCloud was acquired by Lumivero, a Denver, Colorado-based analytics software company also known for products such as XLSTAT and NVivo, and SharpCloud is now sold and supported as part of the Lumivero product portfolio. The platform serves more than 100 organizations and over 18,000 users globally, spanning use cases such as product roadmapping, enterprise portfolio management, innovation management, and Gantt or Kanban-style project tracking, alongside dashboards, custom reporting, and collaboration features like comments and mentions. SharpCloud connects to existing data sources through configurable connectors rather than requiring manual data re-entry, and its visual storytelling approach is designed to make complex interdependencies between projects, risks, and strategic goals easier for non-technical stakeholders to understand. Licensing is role-based across three tiers: Creator, for people who build and manage stories and connectors, with a 2-license minimum; Collaborator, for people who edit and maintain data, with a 5-license minimum; and Read-Only, for stakeholders who only need to view and comment, with a 50-license minimum. All licenses are billed annually, and public pricing for the entry paid tier starts at 750 British pounds per year. A free version is also available for evaluation.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '3fab6cc8-c5a3-4994-9a63-35d7fa62bebc';

