INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$Scheduling and Dispatch$q$, $q$A visual dispatch board lets office staff assign and reassign jobs to technicians in real time based on skills, location, and availability.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$Technician Mobile App$q$, $q$Field technicians access job details, customer history, pricebook items, and payment collection from a dedicated mobile app.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$CRM and Customer History$q$, $q$Every customer record includes past jobs, equipment installed, service agreements, and communication history.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$Marketing Automation and Call Tracking$q$, $q$Tracks marketing spend against booked revenue and automates follow-up campaigns and review requests.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$Pricebook and Flat-Rate Pricing$q$, $q$A configurable pricebook standardizes flat-rate pricing and upsell options across technicians and crews.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$Invoicing, Payments, and Financing$q$, $q$Technicians can invoice, collect payment, and offer customer financing options directly from the field.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$Inventory and Fleet Management$q$, $q$Tracks truck stock, warehouse inventory, and purchase orders tied to specific jobs.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$Reporting and Business Analytics$q$, $q$Dashboards roll up performance across technicians, crews, and locations for owners and managers.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$Extremely deep, trades-specific feature set spanning nearly every back-office and field workflow$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$Strong marketing and call-tracking tools tied directly to revenue attribution$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$Well-built mobile app designed around how field technicians actually work$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$Established, publicly traded vendor with a large customer base across the trades industry$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$Pricing is not published and can be expensive once onboarding fees are included$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$Steep learning curve and lengthy implementation timeline for new customers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$Long-term annual contracts can make switching providers difficult$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$Built primarily for larger multi-technician operations, more than many small or solo businesses need$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$What is ServiceTitan used for?$q$, $q$ServiceTitan is used by trades businesses like HVAC, plumbing, electrical, and roofing companies to manage scheduling, dispatch, CRM, marketing, invoicing, and payments in one platform.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$How much does ServiceTitan cost?$q$, $q$ServiceTitan uses custom, quote-based pricing rather than published plans. Third-party sources report starting costs around 398 dollars per month, with all-in per-technician costs often between roughly 300 and 500-plus dollars per month, plus onboarding fees.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$Does ServiceTitan offer a free trial?$q$, $q$ServiceTitan does not publicly advertise a self-serve free trial; prospective customers typically go through a sales demo and custom quote process.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$What industries does ServiceTitan serve?$q$, $q$ServiceTitan primarily serves residential and commercial trades businesses including HVAC, plumbing, electrical, roofing, garage door, and chimney companies.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$Is ServiceTitan the same as ServiceNow?$q$, $q$No. ServiceTitan is trades-focused field service management software, while ServiceNow is an unrelated enterprise IT service management company. The names are similar but the companies and products are completely different.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$Does ServiceTitan integrate with QuickBooks?$q$, $q$Yes, ServiceTitan offers integration with QuickBooks for syncing accounting and financial data.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$Is ServiceTitan publicly traded?$q$, $q$Yes. ServiceTitan went public on the Nasdaq under the ticker TTAN in December 2024.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$What size business is ServiceTitan best suited for?$q$, $q$ServiceTitan is generally best suited for established trades businesses with multiple technicians and trucks rather than solo operators or very small teams.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$HVAC Company Dispatch and Scheduling$q$, $q$An HVAC company with multiple crews uses ServiceTitan's dispatch board to assign emergency and scheduled jobs to the nearest available technician.$q$, $q$HVAC business owners and dispatchers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$Plumbing Business Marketing ROI$q$, $q$A plumbing company tracks which marketing campaigns and phone numbers generate booked revenue using ServiceTitan's call tracking and reporting.$q$, $q$Plumbing company marketing managers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$Electrical Contractor Field Payments$q$, $q$An electrical contractor's technicians invoice and collect payment on-site immediately after completing a job using the mobile app.$q$, $q$Electrical contractors and field technicians$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$Standard (Custom Quote)$q$, $q$Custom pricing, contact sales$q$, $q$Annual contract$q$, NULL, $q$["Scheduling and dispatch","CRM and customer history","Mobile technician app","Basic invoicing and payments","Core reporting"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$Enterprise (Custom Quote)$q$, $q$Custom pricing, contact sales$q$, $q$Annual contract$q$, NULL, $q$["All Standard features","Marketing automation and call tracking","Inventory and fleet management","Advanced business analytics","Multi-location reporting and support"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$overview$q$, $q$What Is ServiceTitan$q$, 2, ARRAY[$q$ServiceTitan is a cloud-based business management platform built specifically for the trades: HVAC, plumbing, electrical, roofing, garage door, chimney, and similar home and commercial service companies. Rather than stitching together separate scheduling, CRM, invoicing, and marketing tools, ServiceTitan puts all of these workflows into a single system that call center staff, dispatchers, technicians, and owners share in real time.$q$, $q$Founded in 2007 by Ara Mahdessian and Vahe Kuzoyan and headquartered in Glendale, California, ServiceTitan grew into one of the largest software vendors serving the trades industry before going public on the Nasdaq in December 2024 under the ticker TTAN. It is generally positioned for established trades businesses running multiple trucks and technicians rather than solo operators just getting started.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$ServiceTitan covers the full job lifecycle: call booking and intake, drag-and-drop dispatch and scheduling boards, a technician mobile app with route optimization, a configurable pricebook for flat-rate pricing and upsells, and on-site invoicing with integrated payment and financing options.$q$, $q$On the back office side, the platform includes CRM with full customer and equipment history, marketing automation tied to call tracking and campaign ROI reporting, inventory and truck stock management, and business intelligence dashboards that roll performance up across technicians, crews, and locations.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6fc3837d-ade3-437f-ac16-1a4ee783c3f8', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$ServiceTitan does not publish fixed pricing tiers. Costs are quoted per business based on the number of technicians, the modules enabled, and contract length, and are typically billed under an annual agreement rather than month to month.$q$, $q$Third-party operator reports and review sites cite starting costs around 398 dollars per month, with all-in per-technician costs commonly landing between roughly 300 and 500-plus dollars per month, plus a separate onboarding and implementation fee that can range from a few thousand to tens of thousands of dollars depending on company size.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ebd42bbd-e0eb-4348-9dec-c85d892145d6', $q$Custom CFP Submission Forms$q$, $q$Organizers build tailored submission forms to collect talk proposals with their own required fields.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ebd42bbd-e0eb-4348-9dec-c85d892145d6', $q$Speaker Profile Directory$q$, $q$Speakers maintain one reusable profile with bio, photo, and past sessions across multiple events.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ebd42bbd-e0eb-4348-9dec-c85d892145d6', $q$Session Review and Voting$q$, $q$Reviewers can score, comment on, and vote on submitted session proposals.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ebd42bbd-e0eb-4348-9dec-c85d892145d6', $q$Event Schedule Builder$q$, $q$Accepted sessions can be arranged into a public-facing event schedule automatically.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ebd42bbd-e0eb-4348-9dec-c85d892145d6', $q$Speaker Communication Tools$q$, $q$Built-in messaging lets organizers notify speakers of acceptance, rejection, or schedule details.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ebd42bbd-e0eb-4348-9dec-c85d892145d6', $q$Public Event and Speaker Pages$q$, $q$Each event gets a public page listing sessions, speakers, and schedule details.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ebd42bbd-e0eb-4348-9dec-c85d892145d6', $q$Multi-Event Speaker Reuse$q$, $q$Speakers can apply to many different Sessionize-powered events without re-entering their information.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ebd42bbd-e0eb-4348-9dec-c85d892145d6', $q$Submission Analytics$q$, $q$Organizers can review submission volume and reviewer activity throughout the CFP window.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ebd42bbd-e0eb-4348-9dec-c85d892145d6', $q$Purpose-built specifically for CFP and speaker management rather than general event ticketing$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ebd42bbd-e0eb-4348-9dec-c85d892145d6', $q$Free for non-commercial community events$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ebd42bbd-e0eb-4348-9dec-c85d892145d6', $q$Widely adopted across the tech conference circuit, so many speakers already have profiles$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ebd42bbd-e0eb-4348-9dec-c85d892145d6', $q$No credit card required to test the platform before paying$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ebd42bbd-e0eb-4348-9dec-c85d892145d6', $q$Commercial event fee is a flat 499 dollars per event regardless of event size$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ebd42bbd-e0eb-4348-9dec-c85d892145d6', $q$Feature set is narrowly focused on CFP and scheduling, not full event ticketing or registration$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ebd42bbd-e0eb-4348-9dec-c85d892145d6', $q$Very small company size means limited support bandwidth compared to larger event platforms$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ebd42bbd-e0eb-4348-9dec-c85d892145d6', $q$Bulk and agency pricing is not published and requires a custom conversation$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ebd42bbd-e0eb-4348-9dec-c85d892145d6', $q$What is Sessionize used for?$q$, $q$Sessionize is used to manage a conference or event's call for papers, review and vote on speaker submissions, and build the public event schedule and speaker directory.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ebd42bbd-e0eb-4348-9dec-c85d892145d6', $q$Is Sessionize free?$q$, $q$Sessionize is free for non-commercial community events with no participation fee. Commercial or for-profit events pay a flat 499 US dollar fee per event.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ebd42bbd-e0eb-4348-9dec-c85d892145d6', $q$How much does Sessionize cost for a paid conference?$q$, $q$Commercial events pay 499 US dollars plus tax per event occurrence, which unlocks the full Sessionize feature set.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ebd42bbd-e0eb-4348-9dec-c85d892145d6', $q$Do speakers need to pay to use Sessionize?$q$, $q$No. Speakers create a free profile and submit talks to events at no cost; only event organizers running commercial events pay a fee.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ebd42bbd-e0eb-4348-9dec-c85d892145d6', $q$Where is Sessionize based?$q$, $q$Sessionize was founded in 2017 and is headquartered in Zagreb, Croatia.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ebd42bbd-e0eb-4348-9dec-c85d892145d6', $q$Does Sessionize require a credit card to try?$q$, $q$No. Sessionize offers a fully functional test mode that does not require a credit card.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ebd42bbd-e0eb-4348-9dec-c85d892145d6', $q$Can agencies running multiple events get discounted pricing?$q$, $q$Yes. Organizations running five or more events per year can arrange custom bulk pricing with pre-purchased activation codes.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ebd42bbd-e0eb-4348-9dec-c85d892145d6', $q$Is Sessionize only for tech conferences?$q$, $q$Sessionize is most widely adopted in the technology and developer conference community, but it can be used for any event that needs CFP and speaker management.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ebd42bbd-e0eb-4348-9dec-c85d892145d6', $q$Developer Conference CFP$q$, $q$A mid-size developer conference uses Sessionize to open a call for papers, have reviewers score submissions, and publish the final agenda.$q$, $q$Tech conference organizers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ebd42bbd-e0eb-4348-9dec-c85d892145d6', $q$Community Meetup Speaker Directory$q$, $q$A recurring local meetup group uses Sessionize's free community-event tier to collect talk proposals each month.$q$, $q$Meetup and user group organizers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ebd42bbd-e0eb-4348-9dec-c85d892145d6', $q$Multi-Event Agency Management$q$, $q$An events agency running a dozen commercial conferences per year uses Sessionize's bulk activation codes to manage CFPs across all of them.$q$, $q$Event agencies and corporate event teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ebd42bbd-e0eb-4348-9dec-c85d892145d6', $q$Community Event$q$, $q$Free$q$, $q$Per event$q$, NULL, $q$["For non-commercial events with no participation fee","Full CFP and speaker management feature set","Requires a Sessionize backlink on the event page","Not for internal, promotional, or profit-generating events"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ebd42bbd-e0eb-4348-9dec-c85d892145d6', $q$Professional Event$q$, $q$$499 USD plus tax$q$, $q$Per event occurrence$q$, NULL, $q$["For commercial and for-profit events","All Sessionize features unlocked","Priority email support","No credit card required to start in test mode"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ebd42bbd-e0eb-4348-9dec-c85d892145d6', $q$Bulk / Agency$q$, $q$Custom pricing$q$, $q$Annual, prepaid activation codes$q$, NULL, $q$["For agencies and corporations running five or more events per year","Pre-purchased activation codes used as needed","Best value for high-volume organizers","Dedicated account support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ebd42bbd-e0eb-4348-9dec-c85d892145d6', $q$overview$q$, $q$What Is Sessionize$q$, 2, ARRAY[$q$Sessionize is a specialized platform for running a call for papers (CFP) process and managing the speakers and schedule for a conference, meetup, or other community event. Instead of collecting talk submissions through email or spreadsheets, organizers use Sessionize to publish a submission form, review proposals, and assemble a final schedule.$q$, $q$Founded in 2017 and based in Zagreb, Croatia, Sessionize is run by a very small, privately held team, but it has become widely used across the technology conference circuit, supporting thousands of events in over 120 countries. Its strength comes from being purpose-built for the CFP and speaker workflow rather than being a general event management or ticketing platform.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ebd42bbd-e0eb-4348-9dec-c85d892145d6', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Organizers can build custom submission forms with their own fields, review and score incoming session proposals, run voting among reviewers, and message accepted or declined speakers directly through the platform. A public event page automatically lists the schedule and speaker bios once sessions are confirmed.$q$, $q$Speakers benefit from a reusable Sessionize profile that stores their photo, bio, and past sessions, so submitting to a new event does not require re-entering the same information. This shared speaker directory is also one of the reasons Sessionize has become popular across many overlapping tech communities.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ebd42bbd-e0eb-4348-9dec-c85d892145d6', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Sessionize is free for community events that do not charge a participation fee, as long as the organizer allows Sessionize backlinking on the event page; it is not intended for internal, promotional, or profit-generating events.$q$, $q$Commercial and for-profit events pay a flat 499 US dollar fee per event occurrence, which unlocks the full feature set and priority email support. Organizations running five or more events per year can negotiate custom bulk pricing using pre-purchased activation codes, and no credit card is required to explore the platform in test mode first.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d498e2a2-205f-436a-b281-0d60d3a97b18', $q$Online Booking Page$q$, $q$A branded page where customers can view availability and book appointments directly.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d498e2a2-205f-436a-b281-0d60d3a97b18', $q$Staff and Service Management$q$, $q$Businesses can add staff members, assign services, and manage individual calendars.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d498e2a2-205f-436a-b281-0d60d3a97b18', $q$Automated Reminders$q$, $q$Email confirmations on the free plan, with SMS reminders added on the Pro plan.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d498e2a2-205f-436a-b281-0d60d3a97b18', $q$Two-Way Calendar Sync$q$, $q$Syncs bookings with Google Calendar and Outlook to avoid double-booking.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d498e2a2-205f-436a-b281-0d60d3a97b18', $q$Video Appointments$q$, $q$Hosts video consultations directly through the platform on the Pro plan.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d498e2a2-205f-436a-b281-0d60d3a97b18', $q$Payment Processing$q$, $q$Accepts online and in-person payments via Square, Stripe, PayPal, and LawPay.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d498e2a2-205f-436a-b281-0d60d3a97b18', $q$Mobile Apps$q$, $q$Native iOS and Android apps let staff manage bookings on the go.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d498e2a2-205f-436a-b281-0d60d3a97b18', $q$Team Collaboration Tools$q$, $q$Multiple staff members can manage shared or individual calendars from one account.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d498e2a2-205f-436a-b281-0d60d3a97b18', $q$Genuinely usable free plan for up to 4 users, not just a limited trial$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d498e2a2-205f-436a-b281-0d60d3a97b18', $q$Low-cost Pro plan starting at 5 dollars per user per month annually$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d498e2a2-205f-436a-b281-0d60d3a97b18', $q$Built-in video appointments and payment processing without extra software$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d498e2a2-205f-436a-b281-0d60d3a97b18', $q$Broad integration support including Zapier, Mailchimp, and HubSpot$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d498e2a2-205f-436a-b281-0d60d3a97b18', $q$Free plan is capped at 200 appointments per month and 4 users$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d498e2a2-205f-436a-b281-0d60d3a97b18', $q$Monthly (non-annual) Pro pricing is notably higher at 12 dollars per user$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d498e2a2-205f-436a-b281-0d60d3a97b18', $q$Headquarters and company ownership details are not consistently published$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d498e2a2-205f-436a-b281-0d60d3a97b18', $q$Advanced customization and reporting are more limited than larger scheduling platforms$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d498e2a2-205f-436a-b281-0d60d3a97b18', $q$Is Setmore really free?$q$, $q$Yes. Setmore's Free plan supports up to 4 users and 200 monthly appointments at no cost, with no trial time limit.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d498e2a2-205f-436a-b281-0d60d3a97b18', $q$How much does Setmore Pro cost?$q$, $q$Setmore Pro starts at 5 US dollars per user per month when billed annually, or 12 dollars per user per month when billed monthly.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d498e2a2-205f-436a-b281-0d60d3a97b18', $q$Does Setmore support online payments?$q$, $q$Yes, Setmore integrates with Square, Stripe, PayPal, and LawPay for accepting online and in-person payments.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d498e2a2-205f-436a-b281-0d60d3a97b18', $q$Can Setmore send text message reminders?$q$, $q$SMS reminders are available on the Pro plan; the Free plan includes email confirmations and reminders.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d498e2a2-205f-436a-b281-0d60d3a97b18', $q$Does Setmore offer video appointments?$q$, $q$Yes, video appointments are included as part of the Pro plan.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d498e2a2-205f-436a-b281-0d60d3a97b18', $q$When was Setmore founded?$q$, $q$Setmore was founded in 2011.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d498e2a2-205f-436a-b281-0d60d3a97b18', $q$Does Setmore have mobile apps?$q$, $q$Yes, Setmore offers native apps for both iOS and Android.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d498e2a2-205f-436a-b281-0d60d3a97b18', $q$What is the Setmore Live Receptionist add-on?$q$, $q$It is an optional add-on, available for US customers at 99 US dollars per month, that provides human receptionists to answer calls and book appointments.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d498e2a2-205f-436a-b281-0d60d3a97b18', $q$Salon and Spa Booking$q$, $q$A salon uses Setmore's free booking page to let clients schedule appointments with specific stylists online.$q$, $q$Salon and spa owners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d498e2a2-205f-436a-b281-0d60d3a97b18', $q$Consultant Video Appointments$q$, $q$An independent consultant uses Setmore Pro to host video consultations and collect payment at time of booking.$q$, $q$Consultants and coaches$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d498e2a2-205f-436a-b281-0d60d3a97b18', $q$Home Service Recurring Appointments$q$, $q$A home cleaning service uses Setmore's recurring appointment feature to automatically rebook regular clients.$q$, $q$Home service businesses$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d498e2a2-205f-436a-b281-0d60d3a97b18', $q$Free$q$, $q$$0$q$, $q$Monthly, up to 4 users$q$, NULL, $q$["Up to 200 appointments per month","Branded online booking page","Email confirmations and reminders","iOS and Android apps","Accept online and in-person payments","Basic integrations with Mailchimp, HubSpot, Zapier, and GA4"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d498e2a2-205f-436a-b281-0d60d3a97b18', $q$Pro$q$, $q$$5 per user per month billed annually ($12 per user per month billed monthly)$q$, $q$Monthly or annual, unlimited users$q$, NULL, $q$["Unlimited appointments","Remove Setmore branding","SMS reminders","Two-way calendar sync","Recurring and video appointments","API access and priority support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d498e2a2-205f-436a-b281-0d60d3a97b18', $q$Live Receptionist Add-on$q$, $q$$99 per month$q$, $q$Monthly add-on, available with Free or Pro, US only$q$, NULL, $q$["Human receptionists answer and book calls","Available as an add-on to any plan","US-based service"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d498e2a2-205f-436a-b281-0d60d3a97b18', $q$overview$q$, $q$What Is Setmore$q$, 2, ARRAY[$q$Setmore is an online appointment scheduling platform aimed at small and medium service businesses, including salons, spas, healthcare and wellness practices, consultants, tutors, and home service providers. It provides a branded online booking page that customers can use to book appointments directly, without phone calls or back-and-forth emails.$q$, $q$Founded in 2011, Setmore is a small, privately held company best known in the scheduling software category for offering a genuinely usable free plan rather than a stripped-down trial, which has made it a common recommendation for businesses booking their first online scheduling tool.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d498e2a2-205f-436a-b281-0d60d3a97b18', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core features include staff and service management, a customizable booking page, automated email and SMS reminders, two-way calendar sync with Google and Outlook, recurring appointments, and built-in video appointments for remote consultations.$q$, $q$Setmore also supports payment collection through Square, Stripe, PayPal, and LawPay, mobile apps for iOS and Android, and integrations with Mailchimp, HubSpot, Zapier, and Google Analytics 4, plus an optional US-based live receptionist add-on for businesses that want human call handling alongside online booking.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d498e2a2-205f-436a-b281-0d60d3a97b18', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Setmore's Free plan costs nothing and supports up to 4 staff users, up to 200 monthly appointments, a branded booking page, reminders, and mobile apps, with no time limit on how long a business can stay on it.$q$, $q$The Pro plan starts at 5 US dollars per user per month when billed annually, or 12 dollars per user per month billed monthly, and removes the appointment cap and Setmore branding while adding SMS reminders, two-way calendar sync, recurring and video appointments, and API access. A Live Receptionist add-on is available for 99 US dollars per month for US-based businesses.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2d77d287-461d-4b2b-b185-9fa78b3a2e55', $q$Reservation and Waitlist Management$q$, $q$Branded online reservations and a digital waitlist reduce phone-based booking and no-shows.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2d77d287-461d-4b2b-b185-9fa78b3a2e55', $q$Table Management$q$, $q$A visual floor plan lets hosts assign and optimize tables in real time.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2d77d287-461d-4b2b-b185-9fa78b3a2e55', $q$Guest CRM and Preferences$q$, $q$Detailed guest profiles capture dining history, allergies, and special occasions for personalized service.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2d77d287-461d-4b2b-b185-9fa78b3a2e55', $q$Marketing Automation$q$, $q$Automated email and text campaigns target guests based on visit history and preferences.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2d77d287-461d-4b2b-b185-9fa78b3a2e55', $q$Reservation Marketplace Access$q$, $q$Listings reach DoorDash and Deliveroo diners without per-cover marketplace fees.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2d77d287-461d-4b2b-b185-9fa78b3a2e55', $q$Reputation Management$q$, $q$Consolidates and helps respond to guest reviews across platforms.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2d77d287-461d-4b2b-b185-9fa78b3a2e55', $q$Event Management$q$, $q$Tools for managing private dining and event bookings alongside regular reservations.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2d77d287-461d-4b2b-b185-9fa78b3a2e55', $q$WhatsApp and Text Marketing$q$, $q$An optional add-on for messaging guests directly via WhatsApp and SMS.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2d77d287-461d-4b2b-b185-9fa78b3a2e55', $q$Deep guest CRM that supports genuine personalization across repeat visits$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2d77d287-461d-4b2b-b185-9fa78b3a2e55', $q$Access to DoorDash and Deliveroo reservation marketplace traffic without per-cover fees$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2d77d287-461d-4b2b-b185-9fa78b3a2e55', $q$Covers reservations, table management, and marketing in one connected system$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2d77d287-461d-4b2b-b185-9fa78b3a2e55', $q$Backed by significant funding and now part of DoorDash's broader hospitality ecosystem$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2d77d287-461d-4b2b-b185-9fa78b3a2e55', $q$Pricing is not published and requires a sales conversation to obtain a quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2d77d287-461d-4b2b-b185-9fa78b3a2e55', $q$Reported starting cost of around 499 dollars per month per venue may be high for very small independent restaurants$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2d77d287-461d-4b2b-b185-9fa78b3a2e55', $q$Some advanced marketing and messaging features are priced as separate add-ons$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2d77d287-461d-4b2b-b185-9fa78b3a2e55', $q$Acquisition by DoorDash in 2025 may bring future changes to product direction or data handling$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2d77d287-461d-4b2b-b185-9fa78b3a2e55', $q$What is SevenRooms used for?$q$, $q$SevenRooms is used by restaurants, hotels, and nightlife venues to manage reservations, waitlists, table assignments, guest CRM, and marketing in one platform.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2d77d287-461d-4b2b-b185-9fa78b3a2e55', $q$How much does SevenRooms cost?$q$, $q$SevenRooms uses custom, quote-based pricing per venue. Third-party sources report the core platform commonly starting around 499 US dollars per month on an annual contract.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2d77d287-461d-4b2b-b185-9fa78b3a2e55', $q$Who owns SevenRooms?$q$, $q$SevenRooms was founded independently in 2011. In May 2025, DoorDash announced an agreement to acquire SevenRooms for approximately 1.2 billion dollars.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2d77d287-461d-4b2b-b185-9fa78b3a2e55', $q$Does SevenRooms charge cover fees for reservation marketplace bookings?$q$, $q$No, SevenRooms provides access to DoorDash and Deliveroo's tens of millions of diners without per-cover marketplace fees.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2d77d287-461d-4b2b-b185-9fa78b3a2e55', $q$Where is SevenRooms headquartered?$q$, $q$SevenRooms is headquartered in New York City, with additional offices in the UK, Dubai, Australia, Singapore, and Hong Kong.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2d77d287-461d-4b2b-b185-9fa78b3a2e55', $q$Does SevenRooms support marketing campaigns?$q$, $q$Yes, SevenRooms includes email and text marketing automation, plus optional WhatsApp messaging as an add-on.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2d77d287-461d-4b2b-b185-9fa78b3a2e55', $q$When was SevenRooms founded?$q$, $q$SevenRooms was founded in 2011 by Joel Montaniel, Allison Page, and Kinesh Patel.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2d77d287-461d-4b2b-b185-9fa78b3a2e55', $q$What businesses use SevenRooms?$q$, $q$SevenRooms is used primarily by restaurants, hotels, and nightlife and entertainment venues.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2d77d287-461d-4b2b-b185-9fa78b3a2e55', $q$Restaurant Reservations and Waitlist$q$, $q$A busy restaurant uses SevenRooms to manage online reservations and a digital waitlist during peak hours.$q$, $q$Restaurant owners and hosts$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2d77d287-461d-4b2b-b185-9fa78b3a2e55', $q$Hotel Guest Personalization$q$, $q$A hotel's dining outlet uses SevenRooms' guest CRM to track VIP preferences and special occasions across visits.$q$, $q$Hotel food and beverage managers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2d77d287-461d-4b2b-b185-9fa78b3a2e55', $q$Nightlife Venue Marketing$q$, $q$A nightlife venue uses SevenRooms' marketing automation and reservation marketplace access to fill tables on slower nights.$q$, $q$Nightlife and entertainment venue operators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2d77d287-461d-4b2b-b185-9fa78b3a2e55', $q$Starter$q$, $q$Custom quote$q$, $q$Annual contract, per venue$q$, NULL, $q$["CRM and guest profiles","Branded reservations and waitlist management","Access to DoorDash and Deliveroo reservation marketplace","Table management","Reputation management","Basic marketing automation"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2d77d287-461d-4b2b-b185-9fa78b3a2e55', $q$Growth$q$, $q$Custom quote$q$, $q$Annual contract, per venue$q$, NULL, $q$["All Starter features","Expanded marketing automation","Advanced reporting","Additional third-party integrations"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2d77d287-461d-4b2b-b185-9fa78b3a2e55', $q$Premium$q$, $q$Custom quote$q$, $q$Annual contract, per venue$q$, NULL, $q$["All Growth features","Most advanced automation and personalization tools","Priority support","Access to premium add-ons such as WhatsApp and Voice AI"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2d77d287-461d-4b2b-b185-9fa78b3a2e55', $q$overview$q$, $q$What Is SevenRooms$q$, 2, ARRAY[$q$SevenRooms is a hospitality operations platform that gives restaurants, hotels, and nightlife venues one system for managing reservations, waitlists, table assignments, guest profiles, and marketing. It is built for operators who want to understand and market to individual guests, not just fill tables.$q$, $q$Founded in 2011 by Joel Montaniel, Allison Page, and Kinesh Patel, SevenRooms is headquartered in New York City and operates internationally with offices in the UK, Dubai, Australia, Singapore, and Hong Kong. In May 2025, DoorDash announced an agreement to acquire SevenRooms for approximately 1.2 billion dollars, tying the platform's guest and reservation data more closely to DoorDash's delivery and marketplace business.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2d77d287-461d-4b2b-b185-9fa78b3a2e55', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$SevenRooms provides branded online reservations and waitlist management, drag-and-drop table management, and a guest CRM that stores dining history, preferences, and special occasion notes so staff can personalize service on repeat visits.$q$, $q$Marketing tools include automated email and text campaigns, reputation management for reviews, and access to a reservation marketplace with tens of millions of DoorDash and Deliveroo users at no cover fee. Optional add-ons extend the platform with WhatsApp and text marketing, voice AI, event management, and API integrations.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2d77d287-461d-4b2b-b185-9fa78b3a2e55', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$SevenRooms does not publish fixed pricing; venues request a custom quote, and pricing is set per venue based on the modules and volume required, typically under an annual contract.$q$, $q$Third-party operator reports and review sites indicate the core platform commonly starts around 499 US dollars per month per venue, with optional add-ons such as WhatsApp messaging priced separately at roughly 100 dollars per month.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0c2a2dac-cd9a-4339-9ab2-dfd365b2be95', $q$Flat-File Storage$q$, $q$Bookmarks are stored in flat files rather than a database, simplifying installation and hosting.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0c2a2dac-cd9a-4339-9ab2-dfd365b2be95', $q$One-Click Bookmarklet$q$, $q$A browser bookmarklet lets users save the current page as a bookmark in one click.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0c2a2dac-cd9a-4339-9ab2-dfd365b2be95', $q$Tagging and Full-Text Search$q$, $q$Bookmarks can be tagged and searched across titles, descriptions, and content.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0c2a2dac-cd9a-4339-9ab2-dfd365b2be95', $q$RSS and ATOM Feeds$q$, $q$Automatically generates feeds so others can follow a user's shared links.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0c2a2dac-cd9a-4339-9ab2-dfd365b2be95', $q$Plugin System$q$, $q$A plugin architecture allows the community to extend Shaarli's core functionality.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0c2a2dac-cd9a-4339-9ab2-dfd365b2be95', $q$Self-Hosted Privacy and Control$q$, $q$Users fully control their own bookmark data on their own server.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0c2a2dac-cd9a-4339-9ab2-dfd365b2be95', $q$LDAP Single-User Login$q$, $q$Supports LDAP authentication for the single-user login model.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0c2a2dac-cd9a-4339-9ab2-dfd365b2be95', $q$Multilingual Interface$q$, $q$The interface is available in English, French, German, and Japanese, among other translations.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0c2a2dac-cd9a-4339-9ab2-dfd365b2be95', $q$Completely free and open source with no paid tiers$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0c2a2dac-cd9a-4339-9ab2-dfd365b2be95', $q$No database server required, making it lightweight to install$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0c2a2dac-cd9a-4339-9ab2-dfd365b2be95', $q$Full data ownership through self-hosting$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0c2a2dac-cd9a-4339-9ab2-dfd365b2be95', $q$Active open-source community maintaining the project with regular releases$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0c2a2dac-cd9a-4339-9ab2-dfd365b2be95', $q$Requires technical skill to install, configure, and maintain a web server$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0c2a2dac-cd9a-4339-9ab2-dfd365b2be95', $q$Designed for a single user rather than team or multi-user use$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0c2a2dac-cd9a-4339-9ab2-dfd365b2be95', $q$No official paid support channel$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0c2a2dac-cd9a-4339-9ab2-dfd365b2be95', $q$Interface is intentionally minimalist rather than feature-rich compared to hosted bookmarking apps$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0c2a2dac-cd9a-4339-9ab2-dfd365b2be95', $q$What is Shaarli?$q$, $q$Shaarli is a free, open-source, self-hosted bookmarking and link-sharing tool written in PHP that stores data in flat files instead of a database.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0c2a2dac-cd9a-4339-9ab2-dfd365b2be95', $q$Is Shaarli free?$q$, $q$Yes, Shaarli is free and open-source software with no paid tiers; the only cost is the web hosting you choose to run it on.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0c2a2dac-cd9a-4339-9ab2-dfd365b2be95', $q$Do I need a database to run Shaarli?$q$, $q$No, Shaarli stores bookmarks in flat files and does not require a separate database server.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0c2a2dac-cd9a-4339-9ab2-dfd365b2be95', $q$Can multiple people share one Shaarli instance?$q$, $q$Shaarli is designed as a single-user tool, though multiple people can view public links; it is not built for multi-user team collaboration.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0c2a2dac-cd9a-4339-9ab2-dfd365b2be95', $q$How do I install Shaarli?$q$, $q$Shaarli is installed by downloading it from GitHub and deploying it on a PHP-capable web host, following the setup wizard on first run.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0c2a2dac-cd9a-4339-9ab2-dfd365b2be95', $q$Is Shaarli still actively maintained?$q$, $q$Yes, the community fork on GitHub is actively maintained, with the latest release being version 0.16.3 as of 2026.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0c2a2dac-cd9a-4339-9ab2-dfd365b2be95', $q$What is the difference between the original Shaarli and the community fork?$q$, $q$The original Shaarli was created by developer Sebastien Sauvage in 2011; a community fork on GitHub has since become the actively developed version of the project.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0c2a2dac-cd9a-4339-9ab2-dfd365b2be95', $q$Does Shaarli support tags and search?$q$, $q$Yes, Shaarli supports tagging bookmarks and full-text search across saved links.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0c2a2dac-cd9a-4339-9ab2-dfd365b2be95', $q$Personal Bookmark Archive$q$, $q$A developer self-hosts Shaarli to save and tag technical articles for later reference.$q$, $q$Developers and self-hosting enthusiasts$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0c2a2dac-cd9a-4339-9ab2-dfd365b2be95', $q$Public Link Blog$q$, $q$A blogger or journalist uses Shaarli as a public link blog to share and comment on interesting articles.$q$, $q$Bloggers and independent writers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0c2a2dac-cd9a-4339-9ab2-dfd365b2be95', $q$Lightweight Research Reference Tool$q$, $q$A student or researcher uses Shaarli to organize and search sources for a project without relying on a third-party service.$q$, $q$Students and researchers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0c2a2dac-cd9a-4339-9ab2-dfd365b2be95', $q$Self-Hosted$q$, $q$Free$q$, $q$One-time self-hosted install$q$, NULL, $q$["Full source code and all features included","No user limits","Community plugin ecosystem","Requires own hosting or server"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0c2a2dac-cd9a-4339-9ab2-dfd365b2be95', $q$Third-Party Managed Hosting$q$, $q$Varies by provider$q$, $q$Depends on hosting provider$q$, NULL, $q$["Some third-party providers offer managed Shaarli hosting","Pricing set independently by hosting providers, not by the Shaarli project","Same core open-source feature set"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0c2a2dac-cd9a-4339-9ab2-dfd365b2be95', $q$overview$q$, $q$What Is Shaarli$q$, 2, ARRAY[$q$Shaarli is a free, open-source bookmarking and link-sharing tool that users install on their own web server rather than signing up for a hosted account. It was created by French developer Sebastien Sauvage and first released in 2011 as a minimalist, database-free alternative to hosted bookmarking services.$q$, $q$The actively maintained version today is a community fork hosted on GitHub, which has continued development after the original project slowed down. Because Shaarli stores links in flat files instead of a database, it can run on almost any basic PHP web host, which is part of why it remains popular among self-hosting enthusiasts.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0c2a2dac-cd9a-4339-9ab2-dfd365b2be95', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Shaarli offers a bookmarklet for saving links with one click, tagging and full-text search across saved links, RSS and ATOM feed generation, and a plugin system for extending functionality. It supports LDAP login for single-user authentication and a responsive interface that still works with JavaScript disabled.$q$, $q$Because it is self-hosted, users retain full control of their bookmark data rather than depending on a third-party service that could shut down or change its terms. The interface is available in multiple languages, including English, French, German, and Japanese.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0c2a2dac-cd9a-4339-9ab2-dfd365b2be95', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Shaarli is completely free and open source, distributed under a free software license with the source code publicly available on GitHub. There are no paid tiers, subscriptions, or premium feature unlocks.$q$, $q$The only ongoing cost is whatever web hosting the user chooses to run Shaarli on, since it must be self-hosted; some third-party hosting providers also offer managed Shaarli hosting for a fee they set independently of the Shaarli project itself.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0c2a2dac-cd9a-4339-9ab2-dfd365b2be95', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0c2a2dac-cd9a-4339-9ab2-dfd365b2be95', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed136ebf-ec30-4027-aba4-c834b251578e', $q$Handheld Auto-Correcting CNC Cutting$q$, $q$Origin retracts or nudges the cutting bit automatically to keep cuts within a small tolerance of the design.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed136ebf-ec30-4027-aba4-c834b251578e', $q$Shaper Studio Design Software$q$, $q$A browser and device-based tool for creating and preparing project files for cutting.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed136ebf-ec30-4027-aba4-c834b251578e', $q$Shaper Hub Project Library$q$, $q$A free online hub where Origin owners can browse, download, and share community project designs.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed136ebf-ec30-4027-aba4-c834b251578e', $q$ShaperTape Positioning System$q$, $q$A printed reference tape and onboard camera track the tool's exact position on the material.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed136ebf-ec30-4027-aba4-c834b251578e', $q$Touchscreen Onboard Display$q$, $q$Shows the design overlaid on the workpiece directly on the tool during cutting.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed136ebf-ec30-4027-aba4-c834b251578e', $q$WiFi and USB File Transfer$q$, $q$Supports software updates and design file transfers over WiFi or USB.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed136ebf-ec30-4027-aba4-c834b251578e', $q$Portable, No Fixed Bed Required$q$, $q$At roughly 21 pounds, Origin can be used directly on a workpiece without a dedicated CNC bed.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed136ebf-ec30-4027-aba4-c834b251578e', $q$Festool Co-Engineered Motor$q$, $q$The router's motor and spindle are co-produced with German tool maker Festool.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ed136ebf-ec30-4027-aba4-c834b251578e', $q$No traditional CNC programming or G-code knowledge required to get started$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ed136ebf-ec30-4027-aba4-c834b251578e', $q$Portable design works directly on a workpiece without a fixed CNC bed$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ed136ebf-ec30-4027-aba4-c834b251578e', $q$Shaper Studio and Shaper Hub software are included free with hardware ownership$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ed136ebf-ec30-4027-aba4-c834b251578e', $q$Auto-correction technology reduces the risk of costly cutting mistakes$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ed136ebf-ec30-4027-aba4-c834b251578e', $q$High upfront hardware cost compared to basic routers or jigs$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ed136ebf-ec30-4027-aba4-c834b251578e', $q$Software and project sharing are built around owning the physical Origin router$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ed136ebf-ec30-4027-aba4-c834b251578e', $q$Some learning curve involved in mastering the tracing and cutting technique$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ed136ebf-ec30-4027-aba4-c834b251578e', $q$Primarily useful for woodworking and fabrication rather than general office or business software needs$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ed136ebf-ec30-4027-aba4-c834b251578e', $q$What is Shaper Origin?$q$, $q$Shaper Origin is a handheld CNC router that combines the form factor of a traditional router with automatic path correction for CNC-level cutting precision.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ed136ebf-ec30-4027-aba4-c834b251578e', $q$Is Shaper Hub free?$q$, $q$Yes, Shaper Hub is a free online library where Shaper Origin owners can browse, download, and share community project designs.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ed136ebf-ec30-4027-aba4-c834b251578e', $q$Do I need CNC experience to use Shaper Origin?$q$, $q$No, Origin is designed so users can trace a design freehand while the tool automatically corrects small deviations, without needing to write CNC code.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ed136ebf-ec30-4027-aba4-c834b251578e', $q$What is ShaperTape?$q$, $q$ShaperTape is a printed reference tape applied to the workpiece that, along with an onboard camera, helps Origin track its exact position while cutting.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ed136ebf-ec30-4027-aba4-c834b251578e', $q$How much does Shaper Origin cost?$q$, $q$The base Shaper Origin starts at 2,899 US dollars, with bundles including accessories ranging up to roughly 5,306 dollars.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ed136ebf-ec30-4027-aba4-c834b251578e', $q$Who manufactures Shaper Origin?$q$, $q$Shaper designs and engineers Origin in California, and the hardware is assembled by German tool maker Festool.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ed136ebf-ec30-4027-aba4-c834b251578e', $q$Can I share my designs with other Shaper owners?$q$, $q$Yes, Shaper Hub lets Origin owners upload and share their own project designs with the broader community.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ed136ebf-ec30-4027-aba4-c834b251578e', $q$Is Shaper Studio available without owning Origin?$q$, $q$Shaper Studio is provided as companion software for Shaper Origin owners; check Shaper's official site for the most current details on standalone access.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ed136ebf-ec30-4027-aba4-c834b251578e', $q$Custom Furniture Inlay Work$q$, $q$A furniture maker uses Shaper Origin and Shaper Studio to design and cut precise inlay patterns without a fixed CNC bed.$q$, $q$Furniture makers and woodworkers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ed136ebf-ec30-4027-aba4-c834b251578e', $q$On-Site Contractor Joinery$q$, $q$A contractor brings Origin to a jobsite to cut custom joinery directly on installed material.$q$, $q$Contractors and finish carpenters$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ed136ebf-ec30-4027-aba4-c834b251578e', $q$Sign-Making and Engraving$q$, $q$A small maker shop uses Shaper Hub designs and Origin to produce custom signage and engraved pieces.$q$, $q$Small maker shops and sign makers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ed136ebf-ec30-4027-aba4-c834b251578e', $q$Shaper Origin (Base)$q$, $q$$2,899$q$, $q$One-time hardware purchase$q$, NULL, $q$["Handheld CNC router with auto-correction","Includes access to Shaper Studio and Shaper Hub software","Free software updates over WiFi or USB","Ships in a stackable Systainer case"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ed136ebf-ec30-4027-aba4-c834b251578e', $q$Shaper Origin Workstation Bundle$q$, $q$From approximately $3,199 to $5,306 depending on configuration$q$, $q$One-time hardware purchase$q$, NULL, $q$["Origin router plus Workstation, Plate, or BenchPilot accessories","Expanded stationary and benchtop cutting capability","Includes the same free Shaper Studio and Shaper Hub software"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ed136ebf-ec30-4027-aba4-c834b251578e', $q$Shaper Studio and Shaper Hub (Software)$q$, $q$Free$q$, $q$Included with Origin ownership$q$, NULL, $q$["Browser and device-based project design tool","Community project library and sharing hub","No separate software subscription required"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ed136ebf-ec30-4027-aba4-c834b251578e', $q$overview$q$, $q$What Is Shaper$q$, 2, ARRAY[$q$Shaper is a hardware and software company best known for Shaper Origin, a handheld CNC router that lets users trace or freehand a cutting path while the tool automatically corrects small deviations to keep the cut precise. Unlike a traditional CNC machine, Origin does not require a fixed bed or workpiece to be clamped inside a machine frame.$q$, $q$The company is commonly cited as founded around 2011 or 2012 by MIT-trained engineers Alec Rivers and Ilan Moyer, and is headquartered in San Francisco, California, with an additional office in Stuttgart, Germany tied to its manufacturing partnership with German tool maker Festool, which assembles the Origin hardware.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ed136ebf-ec30-4027-aba4-c834b251578e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Origin uses an onboard camera and a printed reference tape system called ShaperTape to track the tool's position on the workpiece in real time, along with a touchscreen display showing the design overlaid on the material as the user cuts.$q$, $q$The companion software includes Shaper Studio, a browser and device-based design tool for creating and preparing cut files, and Shaper Hub, a free online library and community where Origin owners can browse, download, and share project designs made by other makers.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ed136ebf-ec30-4027-aba4-c834b251578e', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$The base Shaper Origin router starts at 2,899 US dollars, with free shipping, excluding tax. Bundle configurations that add accessories like the Workstation, Plate, or BenchPilot systems range from roughly 3,199 to 5,306 dollars depending on the combination chosen.$q$, $q$Shaper Studio and Shaper Hub are provided free to Origin owners rather than sold as a separate subscription, so the primary cost of adopting the Shaper ecosystem is the one-time hardware purchase rather than a recurring software fee.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Encrypted Cloud Storage$q$, $q$Files are stored with encryption and unlimited storage available on most plans.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Branded Client Portals$q$, $q$Password-protected, branded portals let clients securely upload and download files.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$E-Signature Collection$q$, $q$Built-in e-signature tools let businesses collect signed documents without a separate tool.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Workflow Automation$q$, $q$Automates recurring document workflows such as engagement letters and client onboarding.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Real-Time Co-Editing$q$, $q$Multiple users can collaborate on documents within ShareFile in real time.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Compliance Support$q$, $q$Supports HIPAA, FINRA, and SEC recordkeeping requirements for regulated industries.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Virtual Data Rooms$q$, $q$A dedicated tier adds watermarking, granular permissions, and NDA enforcement for confidential deals.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Mobile and Desktop Sync Apps$q$, $q$Apps for major platforms keep files synced across devices.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Strong compliance support for regulated industries like accounting, legal, and healthcare$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Purpose-built Industry Advantage tier for accounting firm workflows$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Wide language support across ten or more locales$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Backed by Progress Software, a large, established, publicly traded vendor$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Public pricing requires a minimum of 3 users, which may not suit solo practitioners$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Higher tiers such as Industry Advantage and Virtual Data Room can be expensive per user$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Recent change of ownership to Progress Software may bring product roadmap changes$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Feature set is heavily geared toward accounting and legal use cases, which may be more than general businesses need$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$What is ShareFile used for?$q$, $q$ShareFile is used by businesses, especially accounting and legal firms, to securely store, share, and manage documents with clients through encrypted storage and branded client portals.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Who owns ShareFile?$q$, $q$ShareFile was created in 2005, acquired by Citrix Systems in 2011, and acquired by Progress Software Corporation in October 2024 for 875 million dollars.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$How much does ShareFile cost?$q$, $q$ShareFile's Advanced plan starts at 16.50 US dollars per user per month billed annually, with higher tiers, Premium, Industry Advantage, and Virtual Data Room, priced up to roughly 77 dollars per user per month.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Does ShareFile support e-signatures?$q$, $q$Yes, e-signature collection is included starting with the Premium plan.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Is ShareFile good for accounting firms?$q$, $q$Yes, ShareFile offers an Industry Advantage tier built specifically for accounting firm workflows, including tax templates and bulk client onboarding.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$What is the minimum number of users for ShareFile?$q$, $q$Most ShareFile plans require a 3-user minimum, while the Virtual Data Room tier requires a 5-user minimum.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Does ShareFile support compliance requirements like HIPAA?$q$, $q$Yes, ShareFile's Premium and higher tiers include support for HIPAA, FINRA, and SEC compliance requirements.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$What languages does ShareFile support?$q$, $q$ShareFile supports English, Spanish, French, German, Japanese, Dutch, Portuguese, Korean, Simplified Chinese, and Russian, among others.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Accounting Firm Client Document Exchange$q$, $q$An accounting firm uses ShareFile's Industry Advantage tier to onboard clients in bulk and automate tax engagement workflows.$q$, $q$Accounting and tax firms$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Law Firm Secure Client Portal$q$, $q$A law firm uses ShareFile's branded client portal to securely exchange case documents with clients.$q$, $q$Legal firms$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Confidential Deal Document Sharing$q$, $q$A company preparing for a merger uses ShareFile's Virtual Data Room tier to share due-diligence documents with watermarking and access tracking.$q$, $q$Corporate development and M&A teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Advanced$q$, $q$$16.50 per user per month billed annually ($18.15 monthly)$q$, $q$Monthly or annual, 3-user minimum$q$, NULL, $q$["Encrypted cloud storage","Email integrations","Real-time co-editing","Granular access controls","Basic reporting"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Premium$q$, $q$$26.00 per user per month billed annually ($28.60 monthly)$q$, $q$Monthly or annual, 3-user minimum$q$, NULL, $q$["All Advanced features","Client collaboration tools and enhanced client portal","E-signatures, requests, tasks, and forms","Workflow automation","HIPAA, FINRA, and SEC compliance support","AI-powered document automation"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Industry Advantage (Accounting)$q$, $q$$41.67 per user per month billed annually ($45.83 monthly)$q$, $q$Monthly or annual, 3-user minimum$q$, NULL, $q$["All Premium features","Pre-built tax workflow templates","Bulk client onboarding","Centralized engagement management","Automated engagement letters","Accounting software integrations"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$Virtual Data Room$q$, $q$$69.30 per user per month billed annually ($77.00 monthly)$q$, $q$Monthly or annual, 5-user minimum$q$, NULL, $q$["Granular permissioning","Real-time activity tracking","Document watermarking","NDA enforcement","Deal-room-ready security"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$overview$q$, $q$What Is ShareFile$q$, 2, ARRAY[$q$ShareFile is a secure, cloud-based file sharing and document workflow platform aimed at professional services businesses, particularly accounting, legal, financial services, and healthcare firms that regularly exchange sensitive documents with clients.$q$, $q$ShareFile was created in November 2005 by Jesse Lipson in Raleigh, North Carolina, acquired by Citrix Systems in 2011, and later acquired by Progress Software Corporation in October 2024 for 875 million dollars, bringing more than 86,000 customers into the Progress product portfolio.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$ShareFile provides encrypted cloud storage, branded and password-protected client portals, real-time co-editing, and granular access controls for managing who can view, edit, or download specific files and folders.$q$, $q$Higher tiers add e-signature collection, form building, task and workflow automation, and compliance support for standards such as HIPAA, FINRA, and SEC recordkeeping, plus accounting-specific workflow templates and a dedicated Virtual Data Room tier for confidential deal and due-diligence documents.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2708453f-26c2-4ab0-9cc3-e26e1734570d', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$ShareFile is sold as a per-user subscription with a 3-user minimum, across four published tiers, Advanced, Premium, Industry Advantage for accounting firms, and Virtual Data Room, which requires a 5-user minimum.$q$, $q$Annual billing lowers the per-user rate compared to monthly billing: Advanced starts at 16.50 dollars per user per month annually versus 18.15 monthly, Premium at 26.00 versus 28.60, Industry Advantage at 41.67 versus 45.83, and Virtual Data Room at 69.30 versus 77.00 per user per month.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3fab6cc8-c5a3-4994-9a63-35d7fa62bebc', $q$Interactive Data Storytelling$q$, $q$Converts spreadsheets and project data into interactive visual stories for stakeholders.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3fab6cc8-c5a3-4994-9a63-35d7fa62bebc', $q$Roadmapping and Portfolio Management$q$, $q$Supports product roadmaps and enterprise portfolio management in one visual view.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3fab6cc8-c5a3-4994-9a63-35d7fa62bebc', $q$Configurable Data Connectors$q$, $q$Pulls data from existing sources rather than requiring manual re-entry.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3fab6cc8-c5a3-4994-9a63-35d7fa62bebc', $q$Risk and Innovation Management$q$, $q$Tracks risks and innovation initiatives alongside broader strategic plans.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3fab6cc8-c5a3-4994-9a63-35d7fa62bebc', $q$Gantt and Kanban Views$q$, $q$Offers timeline and Kanban-style views for project and initiative tracking.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3fab6cc8-c5a3-4994-9a63-35d7fa62bebc', $q$Custom Dashboards and Reporting$q$, $q$Builds custom dashboards and reports from underlying project and portfolio data.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3fab6cc8-c5a3-4994-9a63-35d7fa62bebc', $q$Scenario Planning$q$, $q$Lets teams model and compare different strategic scenarios visually.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3fab6cc8-c5a3-4994-9a63-35d7fa62bebc', $q$Commenting and Collaboration$q$, $q$Stakeholders can comment and mention colleagues directly on visualizations.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3fab6cc8-c5a3-4994-9a63-35d7fa62bebc', $q$Makes complex project and portfolio interdependencies visually digestible for non-technical stakeholders$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3fab6cc8-c5a3-4994-9a63-35d7fa62bebc', $q$Configurable connectors reduce manual data re-entry from existing systems$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3fab6cc8-c5a3-4994-9a63-35d7fa62bebc', $q$Role-based licensing lets organizations control cost by usage type$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3fab6cc8-c5a3-4994-9a63-35d7fa62bebc', $q$Backed by established analytics vendor Lumivero following the January 2026 acquisition$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3fab6cc8-c5a3-4994-9a63-35d7fa62bebc', $q$Public pricing is limited to the entry Creator tier; other tiers require a custom quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3fab6cc8-c5a3-4994-9a63-35d7fa62bebc', $q$Role-based minimums, such as the 50-license Read-Only minimum, may not suit very small teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3fab6cc8-c5a3-4994-9a63-35d7fa62bebc', $q$Less widely known than mainstream roadmapping tools such as Aha! or ProductPlan$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3fab6cc8-c5a3-4994-9a63-35d7fa62bebc', $q$Recent ownership change to Lumivero may bring future shifts in product direction or support$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3fab6cc8-c5a3-4994-9a63-35d7fa62bebc', $q$What is SharpCloud used for?$q$, $q$SharpCloud is used for data visualization, strategic roadmapping, portfolio management, and scenario planning, turning spreadsheets and project data into interactive visual stories.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3fab6cc8-c5a3-4994-9a63-35d7fa62bebc', $q$Who owns SharpCloud now?$q$, $q$SharpCloud was acquired by Lumivero, a Denver-based analytics software company, in January 2026, and is now part of the Lumivero product portfolio.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3fab6cc8-c5a3-4994-9a63-35d7fa62bebc', $q$How much does SharpCloud cost?$q$, $q$SharpCloud's entry-level Creator license starts at 750 British pounds per year; Collaborator and Read-Only tier pricing requires contacting sales.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3fab6cc8-c5a3-4994-9a63-35d7fa62bebc', $q$Does SharpCloud have a free version?$q$, $q$Yes, SharpCloud offers a free version for evaluation alongside its paid tiers.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3fab6cc8-c5a3-4994-9a63-35d7fa62bebc', $q$What is the difference between Creator, Collaborator, and Read-Only licenses?$q$, $q$Creator licenses build and manage stories and connectors, Collaborator licenses edit and maintain data, and Read-Only licenses can only view and comment on stories.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3fab6cc8-c5a3-4994-9a63-35d7fa62bebc', $q$Can SharpCloud connect to existing data sources?$q$, $q$Yes, SharpCloud uses configurable connectors to pull in data from existing sources rather than requiring manual data entry.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3fab6cc8-c5a3-4994-9a63-35d7fa62bebc', $q$Is SharpCloud good for portfolio management?$q$, $q$Yes, SharpCloud is commonly used for enterprise portfolio management, roadmapping, and risk management use cases.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3fab6cc8-c5a3-4994-9a63-35d7fa62bebc', $q$Where is SharpCloud based?$q$, $q$SharpCloud was founded in 2012 and is headquartered in London, United Kingdom.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3fab6cc8-c5a3-4994-9a63-35d7fa62bebc', $q$Enterprise Portfolio Management$q$, $q$An organization visualizes its full project portfolio alongside strategic goals to prioritize investment.$q$, $q$PMO and portfolio managers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3fab6cc8-c5a3-4994-9a63-35d7fa62bebc', $q$Product Roadmapping$q$, $q$A product team builds an interactive roadmap that connects features to underlying strategic themes.$q$, $q$Product managers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3fab6cc8-c5a3-4994-9a63-35d7fa62bebc', $q$Risk and Scenario Planning$q$, $q$A strategy team models different scenarios and associated risks to compare options visually before a decision.$q$, $q$Strategy and risk management teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3fab6cc8-c5a3-4994-9a63-35d7fa62bebc', $q$Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Limited evaluation version of the platform","Core story and visualization creation","Suited to individual trial use"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3fab6cc8-c5a3-4994-9a63-35d7fa62bebc', $q$Creator$q$, $q$From £750 per year$q$, $q$Annual, 2-license minimum$q$, NULL, $q$["Create and manage stories and solutions","Configure data connectors","Edit and maintain data","Explore and filter views","Comment on stories"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3fab6cc8-c5a3-4994-9a63-35d7fa62bebc', $q$Collaborator$q$, $q$Custom pricing$q$, $q$Annual, 5-license minimum$q$, NULL, $q$["Edit and maintain data","Explore and filter views","Comment on stories","For story maintainers who do not build new visualizations"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3fab6cc8-c5a3-4994-9a63-35d7fa62bebc', $q$Read-Only$q$, $q$Custom pricing$q$, $q$Annual, 50-license minimum$q$, NULL, $q$["Explore and filter views","Comment on stories","For stakeholders who only need to view data, no editing rights"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3fab6cc8-c5a3-4994-9a63-35d7fa62bebc', $q$overview$q$, $q$What Is SharpCloud$q$, 2, ARRAY[$q$SharpCloud is a data visualization and strategic portfolio management platform that converts spreadsheets, project plans, and other business data into interactive, story-based visualizations, aimed at making complex interdependencies between projects, risks, and strategic goals easier for stakeholders to understand at a glance.$q$, $q$Founded in 2012 and headquartered in London, United Kingdom, SharpCloud was acquired by Denver-based analytics software company Lumivero in January 2026, and is now sold and supported as part of Lumivero's broader analytics product portfolio, which also includes tools such as XLSTAT and NVivo.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3fab6cc8-c5a3-4994-9a63-35d7fa62bebc', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$SharpCloud supports product roadmapping, enterprise portfolio management, innovation management, and risk management, alongside Gantt and Kanban-style views, custom dashboards, and reporting. Configurable connectors pull in data from existing sources rather than requiring manual re-entry.$q$, $q$Collaboration features such as commenting and mentions let stakeholders discuss specific parts of a visualization directly, and role-based licensing lets organizations control cost by separating story creators from data collaborators and read-only viewers.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3fab6cc8-c5a3-4994-9a63-35d7fa62bebc', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$SharpCloud offers a free version for evaluation, alongside three paid, role-based annual license tiers: Creator, with a 2-license minimum, for people who build stories and configure connectors; Collaborator, with a 5-license minimum, for people who edit and maintain data; and Read-Only, with a 50-license minimum, for stakeholders who only need to view and comment.$q$, $q$Public pricing for the entry-level Creator tier starts at 750 British pounds per year; Collaborator and Read-Only pricing is not publicly listed and requires contacting sales.$q$]::text[], 2);
